// ═══════════════════════════════════════════════════════
// ⚙️  CONFIGURATION — Remplir cette valeur avant utilisation
// ═══════════════════════════════════════════════════════
const N8N_WEBHOOK_BASE = 'https://REMPLACER.n8n.cloud'; // URL de ton instance n8n
// ═══════════════════════════════════════════════════════

const email = $input.first().json;

const fromName  = email.from?.value?.[0]?.name  || '';
const fromEmail = email.from?.value?.[0]?.address || email.from?.text || '';

const parts  = fromName.trim().split(/\s+/);
const prenom = parts[0]  || '';
const nom    = parts.slice(1).join(' ') || '';

const body = email.text
  || (email.html || '').replace(/<[^>]+>/g, ' ').replace(/\s{2,}/g, ' ').trim();

const msgId = (email.messageId || '').replace(/[<>]/g, '') || String(Date.now());

return [{
  json: {
    id: 'imap_' + msgId,
    prenom,
    nom,
    email: fromEmail,
    tel: '',
    bien: '',
    ville: '',
    source: 'email',
    projet: email.subject || '',
    message: body.substring(0, 3000),
    _webhookUrl: N8N_WEBHOOK_BASE + '/webhook/leadflow-traitement'
  }
}];
